export const $predicate = Symbol('predicate');

let predicateId = 0;

/**
 * Create a value-based predicate over one or more dependency traits.
 *
 * The predicate function receives a single array containing each dependency
 * trait's data in declaration order. Every call to `createPredicate` returns a
 * distinct instance, even when the arguments are identical.
 *
 * Tags and relations are not allowed as dependencies because they carry no
 * per-entity value to evaluate.
 */
export function createPredicate<T extends Trait[]>(
    traits: [...T],
    fn: (state: { [K in keyof T]: ReturnType<T[K][typeof $internal]['get']> }) => boolean
): Predicate<T> {
    if (!Array.isArray(traits) || traits.length === 0) {
        throw new Error('Koota: createPredicate requires at least one dependency trait.');
    }

    for (const dep of traits) {
        if (isRelation(dep) || isRelationPair(dep)) {
            throw new Error('Koota: relations cannot be used as createPredicate dependencies.');
        }

        const ctx = (dep as Trait | undefined)?.[$internal];
        if (!ctx) {
            throw new Error('Koota: createPredicate dependencies must be traits.');
        }
        if (ctx.relation) {
            throw new Error('Koota: relations cannot be used as createPredicate dependencies.');
        }
        if (ctx.type === 'tag') {
            throw new Error('Koota: tags cannot be used as createPredicate dependencies.');
        }
    }

    return {
        [$predicate]: true,
        id: predicateId++,
        traits: traits as unknown as Trait[],
        traitIds: (traits as unknown as Trait[]).map((t) => t.id),
        fn: fn as (state: any[]) => boolean,
    } as Predicate<T>;
}

export /* @inline @pure */ function isPredicate(value: unknown): value is Predicate {
    return (value as Brand<typeof $predicate> | null | undefined)?.[
        $predicate
    ] as unknown as boolean;
}

/**
 * Evaluate a predicate against an entity. Returns false if the entity is missing
 * any dependency trait, otherwise the truthiness of the predicate function.
 */
export function evaluatePredicate(world: World, predicate: Predicate, entity: Entity): boolean {
    const deps = predicate.traits;
    const eid = getEntityId(entity);
    const state = new Array(deps.length);

    for (let i = 0; i < deps.length; i++) {
        const trait = deps[i];
        if (!hasTrait(world, entity, trait)) return false;
        const store = getStore(world, trait);
        state[i] = trait[$internal].get(eid, store);
    }

    return !!predicate.fn(state);
}

/**
 * Check the non-predicate static trait constraints (required / forbidden / or)
 * of a predicate query, combining or-traits with or-predicates.
 */
function checkStaticTraits(world: World, query: QueryInstance, entity: Entity): boolean {
    const staticBitmasks = query.staticBitmasks;
    const generations = query.generations;
    const ctx = world[$internal];
    const eid = getEntityId(entity);

    let orTraitMatched = false;

    for (let i = 0; i < generations.length; i++) {
        const generationId = generations[i];
        const bitmask = staticBitmasks[i];
        if (!bitmask) continue;

        const entityMask = ctx.entityMasks[generationId]?.[eid] || 0;

        if (bitmask.forbidden && (entityMask & bitmask.forbidden) !== 0) return false;
        if (bitmask.required && (entityMask & bitmask.required) !== bitmask.required) return false;
        if (bitmask.or !== 0 && (entityMask & bitmask.or) !== 0) orTraitMatched = true;
    }

    // Combined OR pool: at least one or-trait present or one or-predicate satisfied.
    if (query.orHasContent && !orTraitMatched) {
        let matched = false;
        for (let i = 0; i < query.orPredicates.length; i++) {
            if (evaluatePredicate(world, query.orPredicates[i], entity)) {
                matched = true;
                break;
            }
        }
        if (!matched) return false;
    }

    return true;
}

/**
 * Full steady-state membership check for a predicate query (static traits +
 * required / not / or predicates). Relation filters are validated separately.
 */
export function checkPredicateQuery(world: World, query: QueryInstance, entity: Entity): boolean {
    if (!checkStaticTraits(world, query, entity)) return false;

    for (let i = 0; i < query.predicates.length; i++) {
        if (!evaluatePredicate(world, query.predicates[i], entity)) return false;
    }

    for (let i = 0; i < query.notPredicates.length; i++) {
        if (evaluatePredicate(world, query.notPredicates[i], entity)) return false;
    }

    return true;
}

/** Whether an entity passes a query's relation-pair filters. */
function checkRelationFilters(world: World, query: QueryInstance, entity: Entity): boolean {
    if (!query.relationFilters || query.relationFilters.length === 0) return true;
    for (const pair of query.relationFilters) {
        if (!hasRelationPair(world, entity, pair)) return false;
    }
    return true;
}
